{
  "family": "Pinner Reaction",
  "candidate": {
    "substrate_smiles": [
      "CC#N",
      "CCO"
    ],
    "product_smiles": [
      "CC(=[NH2+])OCC.[Cl-]"
    ],
    "optional_reagent_smiles": [
      "Cl"
    ],
    "rationale": "This reaction shows the formation of an imino ether hydrochloride salt (a Pinner salt) from a simple aliphatic nitrile (acetonitrile) and a simple alcohol (ethanol) in the presence of dry hydrogen chloride. This represents the core transformation of the Pinner reaction, which is the acid-catalyzed addition of an alcohol to a nitrile. The resulting Pinner salt is a key intermediate for subsequent hydrolysis to an ester or reaction with ammonia/amines to form amidines.",
    "collision_avoidance_note": "The use of simple, acyclic, saturated aliphatic substrates (acetonitrile and ethanol) avoids overlap with reactions involving aromatic rings, unsaturation, or complex functional groups. The product is the characteristic imino ether salt, which is specific to the Pinner reaction and distinct from the final ester or amidine products that could be confused with other syntheses (e.g., Fischer esterification or direct amidine synthesis)."
  }
}
